import{_ as i,o as a,c as t,ag as e}from"./chunks/framework.DXGyWiRo.js";const r="/media/202508/2025-08-13_155029_4586370.1633225523463805.png",o="/media/202508/2025-08-13_155204_3213810.019037642320511194.png",n="/media/202508/2025-08-13_163340_1876140.9595257615419125.png",s="/media/202508/2025-08-13_163714_6331990.8297526889160832.png",p="/media/202508/2025-08-13_171636_7981520.6488013925351843.png",_="/media/202508/2025-08-13_171810_8896500.35440286304791935.png",c="/media/202508/2025-08-13_171939_7850840.4700167230463125.png",P=JSON.parse('{"title":"语音识别配置","description":"","frontmatter":{"title":"语音识别配置"},"headers":[],"relativePath":"app-config/asr-config.md","filePath":"app-config/asr-config.md","lastUpdated":null}'),u={name:"app-config/asr-config.md"};function d(g,l,m,h,f,b){return a(),t("div",null,[...l[0]||(l[0]=[e('<p>语音识别配置概述</p><p>语音识别配置是AIUI应用提供对链路中使用的语音识别引擎能力进行控制的配置项。其中包括：</p><h2 id="新老应用区分" tabindex="-1">新老应用区分 <a class="header-anchor" href="#新老应用区分" aria-label="Permalink to &quot;新老应用区分&quot;">​</a></h2><p>由于AIUI应用类型的不同，新极速交互类应用和老应用有细微不同：</p><ul><li>新极速类应用 该应用下语音识别配置项不提供识别引擎选型，识别引擎选择放是放在基础配置项下的</li></ul><p><img src="'+r+'" alt="" title="null"></p><ul><li>老应用 该应用下语音识别配置提供识别引擎选择，包括中文普通话、中文方言、英文等识别引擎。</li></ul><p><img src="'+o+'" alt="" title="null"></p><h2 id="语音识别配置" tabindex="-1">语音识别配置 <a class="header-anchor" href="#语音识别配置" aria-label="Permalink to &quot;语音识别配置&quot;">​</a></h2><h3 id="识别引擎选择" tabindex="-1">识别引擎选择 <a class="header-anchor" href="#识别引擎选择" aria-label="Permalink to &quot;识别引擎选择&quot;">​</a></h3><p>在老应用中，语音识别配置项支持识别引擎选择。一般常见的分类方式有：</p><ul><li>按照声学模型分类 <ul><li>中文近场</li><li>中文远场</li></ul></li><li>按照语言分类 <ul><li>中文</li><li>英文</li></ul></li><li>按照中文方言分类 <ul><li>中文普通话</li><li>中文方言（四川话、粤语、东北话……）</li></ul></li></ul><p>另外也支持按照交互场景分类：如 餐饮-中文、车载-中文、智能家居-中文等，这些引擎区别主要是在对应交互领域定向优化了相关的行业名词，提高在对应交互场景下语音交互的识别率。</p><p><img src="'+n+'" alt="" title="null"></p><p><img src="'+s+'" alt="" title="null"></p><h3 id="识别设置" tabindex="-1">识别设置 <a class="header-anchor" href="#识别设置" aria-label="Permalink to &quot;识别设置&quot;">​</a></h3><p>该配置项目主要设置识别引擎结果输出相关类型，不区分应用类型支持的有：</p><ul><li><strong>识别添加标点</strong> 识别结果最后添加标点</li><li><strong>识别结果优先阿拉伯数字</strong> 示例：识别为“1岁”，而不是“一岁”</li><li><strong>progressive 流式识别</strong> 简称 pgs。说话过程中返回多次中间结果，并不断修正。</li></ul><p><img src="'+p+'" alt="" title="null"></p><p>在老应用中还支持有如下特性配置。</p><ul><li><strong>所见即可说</strong> 一次性热词，提高识别率。</li></ul><p><img src="'+_+'" alt="" title="null"></p><h3 id="识别热词" tabindex="-1">识别热词 <a class="header-anchor" href="#识别热词" aria-label="Permalink to &quot;识别热词&quot;">​</a></h3><p>当在语音交互时，识别结果某些名词识别结果不是期望的内容时，可以配置识别热词提高识别率。</p><ul><li><strong>上传识别热词</strong> 永久热词，提高识别率。</li></ul><p><img src="'+c+'" alt="" title="null"></p><h3 id="识别敏感词过滤" tabindex="-1">识别敏感词过滤 <a class="header-anchor" href="#识别敏感词过滤" aria-label="Permalink to &quot;识别敏感词过滤&quot;">​</a></h3><p>该配置项是为了给识别结果做敏感词拦截是使用的，可以自定义设置也支持白名，具体编辑方式可以下载模版了解。</p><ul><li><strong>识别敏感词过滤</strong> 把敏感词过滤成<code>*</code>，不展示给用户，默认关闭。开启后需要解析</li></ul>',29)])])}const x=i(u,[["render",d]]);export{P as __pageData,x as default};
